package com.seaquake6324.civitas.presentation.client;
import com.seaquake6324.civitas.infrastructure.network.PatrolRouteModePayload;import java.util.*;import net.minecraft.client.Minecraft;import net.minecraft.core.BlockPos;import net.minecraft.world.phys.*;
/** Cursor-local route hint. Territory, post and revision validation remain server authoritative. */
public final class PatrolRoutePreview{private static List<BlockPos>nodes=List.of();private static BlockPos target;private static int cap,segmentCap;private static boolean active,locallyValid;
 public static void accept(PatrolRouteModePayload payload){active=payload.active();nodes=payload.nodes();cap=payload.nodeCap();segmentCap=payload.segmentCap();if(!active)clear();}public static void tick(){Minecraft mc=Minecraft.getInstance();if(!active||mc.level==null||!(mc.hitResult instanceof BlockHitResult hit)||hit.getType()!=HitResult.Type.BLOCK){target=null;return;}target=hit.getBlockPos().relative(hit.getDirection()).immutable();boolean standable=mc.level.getBlockState(target).getCollisionShape(mc.level,target).isEmpty()&&mc.level.getBlockState(target.above()).getCollisionShape(mc.level,target.above()).isEmpty()&&mc.level.getBlockState(target.below()).blocksMotion()&&mc.level.getFluidState(target).isEmpty();locallyValid=standable&&nodes.size()<cap&&(nodes.isEmpty()||Math.sqrt(nodes.getLast().distSqr(target))<=segmentCap)&&!(!nodes.isEmpty()&&nodes.getLast().equals(target));}public static boolean active(){return active;}public static List<BlockPos>nodes(){return nodes;}public static BlockPos target(){return target;}public static boolean locallyValid(){return locallyValid;}public static void clear(){active=false;nodes=List.of();target=null;cap=segmentCap=0;locallyValid=false;}private PatrolRoutePreview(){}
}
